import React, { useEffect, useState, useRef, useCallback } from "react";
import heroImage1 from "../../../assets/luen.jpg";
import heroImage2 from "../../../assets/luen_logo.png";
import heroImage3 from "../../../assets/hexagon-main.png";
import "./Carousel.css";

const Carousel = () => {
  const images = [heroImage1, heroImage2, heroImage3];
  
  // Tß║Īo danh s├Īch slide vß╗øi bß║Żn sao ß╗¤ hai ─æß║¦u ─æß╗ā tß║Īo hiß╗ću ß╗®ng v├┤ tß║Łn
  const slides = [images[images.length - 1], ...images, images[0]];

  const [currentIndex, setCurrentIndex] = useState(1);
  const [transition, setTransition] = useState(true);
  const [isAnimating, setIsAnimating] = useState(false);
  const timerRef = useRef(null);

  // H├Ām chuyß╗ān slide tiß║┐p theo - d├╣ng useCallback ─æß╗ā tr├Īnh tß║Īo lß║Īi h├Ām li├¬n tß╗źc
  const nextSlide = useCallback(() => {
    if (isAnimating) return;
    setIsAnimating(true);
    setTransition(true);
    setCurrentIndex((prev) => prev + 1);
  }, [isAnimating]);

  const prevSlide = () => {
    if (isAnimating) return;
    setIsAnimating(true);
    setTransition(true);
    setCurrentIndex((prev) => prev - 1);
  };

  const goToSlide = (index) => {
    if (isAnimating || currentIndex === index + 1) return;
    setIsAnimating(true);
    setTransition(true);
    setCurrentIndex(index + 1);
  };

  // Tß╗▒ ─æß╗Öng chß║Īy slide
  useEffect(() => {
    timerRef.current = setInterval(() => {
      nextSlide();
    }, 3000);

    return () => clearInterval(timerRef.current);
  }, [nextSlide]);

  const handleTransitionEnd = () => {
    setIsAnimating(false);

    // Nß║┐u ─æang ß╗¤ slide cuß╗æi (bß║Żn sao cß╗¦a slide 1), nhß║Ży vß╗ü slide 1 thß║Łt
    if (currentIndex === slides.length - 1) {
      setTransition(false);
      setCurrentIndex(1);
    }

    // Nß║┐u ─æang ß╗¤ slide ─æß║¦u (bß║Żn sao cß╗¦a slide cuß╗æi), nhß║Ży vß╗ü slide cuß╗æi thß║Łt
    if (currentIndex === 0) {
      setTransition(false);
      setCurrentIndex(images.length);
    }
  };

  // X├Īc ─æß╗ŗnh dot n├Āo ─æang active
  // Logic n├Āy gi├║p tr├Īnh viß╗ćc kh├┤ng c├│ dot n├Āo s├Īng khi ─æang ß╗¤ c├Īc slide "clone"
  const getActiveDot = () => {
    if (currentIndex === 0) return images.length - 1;
    if (currentIndex === slides.length - 1) return 0;
    return currentIndex - 1;
  };

  return (
    <div className="carousel">
      <div
        className="carousel-inner"
        style={{
          transform: `translateX(-${currentIndex * 100}%)`,
          transition: transition ? "transform 0.5s ease-in-out" : "none",
        }}
        onTransitionEnd={handleTransitionEnd}
      >
        {slides.map((img, index) => (
          <div className="carousel-item" key={index}>
            <img src={img} alt={`slide-${index}`} />
          </div>
        ))}
      </div>

      <button className="carousel-button prev" onClick={prevSlide} disabled={isAnimating}>
        ŌØ«
      </button>

      <button className="carousel-button next" onClick={nextSlide} disabled={isAnimating}>
        ŌØ»
      </button>

      <div className="carousel-dots">
        {images.map((_, index) => (
          <span
            key={index}
            className={`dot ${getActiveDot() === index ? "active" : ""}`}
            onClick={() => goToSlide(index)}
          ></span>
        ))}
      </div>
    </div>
  );
};

export default Carousel;